            author: msg.sender,
            contentHash: keccak256(abi.encodePacked(content)), // Store content hash instead of full string
            totalPower: 0
        });
        authorBalances[msg.sender] += msg.value;
        emit PostCreated(newPostId, msg.sender, posts[newPostId].contentHash);
    }

    function boostPost(uint256 postId) public payable nonReentrant {
        require(postId < postCount, "Post does not exist");
        require(msg.value > 0, "Boost amount must be greater than zero");
        Post storage post = posts[postId];
        require(post.author != address(0), "Invalid post");

        post.totalPower += msg.value;
        authorBalances[post.author] += msg.value;
        emit PostBoosted(postId, msg.value);
    }

    function authorBalances(address author) public view returns (uint256) {
        return authorBalances[author];
    }

    function withdraw() public nonReentrant {
        uint256 balance = authorBalances[msg.sender];
        require(balance > 0, "No balance to withdraw");
        authorBalances[msg.sender] = 0;
        payable(msg.sender).transfer(balance);
        emit Withdrawal(msg.sender, balance);
    }
}
